public class EnvironmentCleaner {

	public Environment clean(Environment value, String workingDir, String uri) {
		Environment result = new Environment(value);
		for (PropertySource source : value.getPropertySources()) {
			String name = source.getName().replace(workingDir, "");
			name = name.replace("applicationConfig: [", "");
			name = uri + "/" + name.replace("]", "");
			result.add(new PropertySource(name, clean(source.getSource(), uri)));
		}
		return result;
	}

	protected Map<?, ?> clean(Map<?, ?> source, String uri) {
		for (Map.Entry<?, ?> entry : source.entrySet()) {
			if (entry.getValue() instanceof PropertyValueDescriptor) {
				PropertyValueDescriptor descriptor = (PropertyValueDescriptor) entry.getValue();
				if (!uri.endsWith("/")) {
					uri = uri + "/";
				}
				String updated = descriptor.getOrigin().replace("[", "[" + uri);
				descriptor.setOrigin(updated);
			}
		}
		return source;
	}

}

public class AwsEc2ClientAuthenticationProvider extends SpringVaultClientAuthenticationProvider {

	public AwsEc2ClientAuthenticationProvider() {
		super(AuthenticationMethod.AWS_EC2);
	}

	@Override
	public ClientAuthentication getClientAuthentication(VaultEnvironmentProperties vaultProperties,
			RestOperations vaultRestOperations, RestOperations externalRestOperations) {

		VaultEnvironmentProperties.AwsEc2Properties awsEc2 = vaultProperties.getAwsEc2();

		AwsEc2AuthenticationOptions.Nonce nonce = StringUtils.hasText(awsEc2.getNonce())
				? AwsEc2AuthenticationOptions.Nonce.provided(awsEc2.getNonce().toCharArray())
				: AwsEc2AuthenticationOptions.Nonce.generated();

		AwsEc2AuthenticationOptions authenticationOptions = AwsEc2AuthenticationOptions.builder()
			.role(awsEc2.getRole()) //
			.path(awsEc2.getAwsEc2Path()) //
			.nonce(nonce) //
			.identityDocumentUri(URI.create(awsEc2.getIdentityDocument())) //
			.build();

		return new AwsEc2Authentication(authenticationOptions, vaultRestOperations, externalRestOperations);
	}

}

public class SetResponseHeaderGatewayFilterFactory extends AbstractNameValueGatewayFilterFactory {

	@Override
	public GatewayFilter apply(NameValueConfig config) {
		return new GatewayFilter() {
			@Override
			public Mono<Void> filter(ServerWebExchange exchange, GatewayFilterChain chain) {
				String value = ServerWebExchangeUtils.expand(exchange, config.getValue());
				String name = Objects.requireNonNull(config.name, "name must not be null");
				return chain.filter(exchange)
					.then(Mono.fromRunnable(() -> exchange.getResponse().getHeaders().set(name, value)));
			}

			@Override
			public String toString() {
				String name = config.getName();
				String value = config.getValue();
				return filterToStringCreator(SetResponseHeaderGatewayFilterFactory.this)
					.append(name != null ? name : "", value != null ? value : "")
					.toString();
			}
		};
	}

}

public class ObservationClosingWebExceptionHandler implements WebExceptionHandler {

	private static final LogAccessor log = new LogAccessor(ObservationClosingWebExceptionHandler.class);

	@Override
	public Mono<Void> handle(ServerWebExchange exchange, Throwable ex) {
		Object attribute = exchange.getAttribute(ObservedResponseHttpHeadersFilter.OBSERVATION_STOPPED);
		if (attribute == null) {
			Observation observation = exchange.getAttribute(ServerWebExchangeUtils.GATEWAY_OBSERVATION_ATTR);
			if (observation != null) {
				if (log.isDebugEnabled()) {
					observation.scoped(() -> log.debug(
							() -> "An exception occurred and observation was not previously stopped, will stop it. The exception was ["
									+ ex + "]"));
				}
				observation.error(ex);
				observation.stop();
			}
		}
		return Mono.error(ex);
	}

}

