@ConditionalOnMissingBean(HttpClient.class)
public class Http2ClientFeignConfiguration {

	@Bean
	@ConditionalOnMissingBean
	public HttpClient.Builder httpClientBuilder(FeignHttpClientProperties httpClientProperties) {
		return HttpClient.newBuilder()
			.followRedirects(
					httpClientProperties.isFollowRedirects() ? HttpClient.Redirect.ALWAYS : HttpClient.Redirect.NEVER)
			.version(HttpClient.Version.valueOf(httpClientProperties.getHttp2().getVersion()))
			.connectTimeout(Duration.ofMillis(httpClientProperties.getConnectionTimeout()));
	}

	@Bean
	public HttpClient httpClient(HttpClient.Builder httpClientBuilder, List<Http2ClientCustomizer> customizers) {
		customizers.forEach(customizer -> customizer.customize(httpClientBuilder));
		return httpClientBuilder.build();
	}

}

public class AmqpRuntimeHints implements RuntimeHintsRegistrar {

	@Override
	public void registerHints(RuntimeHints hints, @Nullable ClassLoader classLoader) {
		ProxyHints proxyHints = hints.proxies();
		proxyHints.registerJdkProxy(MessageListener.class);

		ReflectionHints reflection = hints.reflection();

		Method protonLink = ReflectionUtils.findMethod(ClientReceiver.class, "protonLink");
		Method getCreditState = ReflectionUtils.findMethod(ProtonReceiver.class, "getCreditState");
		Method writeFlow =
				ReflectionUtils.findMethod(ProtonSessionIncomingWindow.class, "writeFlow", ProtonReceiver.class);

		Stream.of(protonLink, getCreditState, writeFlow)
				.forEach(method -> reflection.registerMethod(method, ExecutableMode.INVOKE));

		Field sessionWindow = ReflectionUtils.findField(ProtonReceiver.class, "sessionWindow");
		if (sessionWindow != null) {
			reflection.registerField(sessionWindow);
		}
	}

}

public class DirectExchangeParser extends AbstractExchangeParser {

	private static final String BINDING_KEY_ATTR = "key";

	@Override
	protected Class<?> getBeanClass(Element element) {
		return DirectExchange.class;
	}

	@Override
	protected BeanDefinitionBuilder parseBinding(String exchangeName, Element binding,
												 ParserContext parserContext) {
		BeanDefinitionBuilder builder = BeanDefinitionBuilder.genericBeanDefinition(BindingFactoryBean.class);
		parseDestination(binding, parserContext, builder);
		builder.addPropertyValue("exchange", new TypedStringValue(exchangeName));
		String queueId = binding.getAttribute(BINDING_QUEUE_ATTR);
		String exchangeId = binding.getAttribute(BINDING_EXCHANGE_ATTR);

		String bindingKey = binding.hasAttribute(BINDING_KEY_ATTR) ? binding.getAttribute(BINDING_KEY_ATTR) :
				"#{@'" + (StringUtils.hasText(queueId) ? queueId : exchangeId)  + "'.name}";

		builder.addPropertyValue("routingKey", new TypedStringValue(bindingKey));
		return builder;
	}

}

public class SpringPropDepsIdeaPlugin implements Plugin<Project> {
	@Override
	public void apply(Project project) {
		PluginManager pluginManager = project.getPluginManager();
		pluginManager.apply(SpringPropDepsPlugin.class);
		pluginManager.apply(IdeaPlugin.class);

		IdeaModel ideaModel = project.getExtensions().getByType(IdeaModel.class);
		ideaModel.module((idea) -> {
			// IDEA internally deals with 4 scopes : COMPILE, TEST, PROVIDED, RUNTIME
			// but only PROVIDED seems to be picked up
			idea.getScopes().get("PROVIDED").get("plus").add(project.getConfigurations().getByName("provided"));
			idea.getScopes().get("PROVIDED").get("plus").add(project.getConfigurations().getByName("optional"));
		});
	}
}

final class OAuth2AuthorizationCodeGenerator implements OAuth2TokenGenerator<OAuth2AuthorizationCode> {

	private final StringKeyGenerator authorizationCodeGenerator = new Base64StringKeyGenerator(
			Base64.getUrlEncoder().withoutPadding(), 96);

	@Nullable
	@Override
	public OAuth2AuthorizationCode generate(OAuth2TokenContext context) {
		if (context.getTokenType() == null || !OAuth2ParameterNames.CODE.equals(context.getTokenType().getValue())) {
			return null;
		}
		Instant issuedAt = Instant.now();
		Instant expiresAt = issuedAt
			.plus(context.getRegisteredClient().getTokenSettings().getAuthorizationCodeTimeToLive());
		return new OAuth2AuthorizationCode(this.authorizationCodeGenerator.generateKey(), issuedAt, expiresAt);
	}

}

final class OidcAuthenticationProviderUtils {

	private OidcAuthenticationProviderUtils() {
	}

	static <T extends OAuth2Token> OAuth2AccessToken accessToken(OAuth2Authorization.Builder builder, T token,
			OAuth2TokenContext accessTokenContext) {

		OAuth2AccessToken accessToken = new OAuth2AccessToken(OAuth2AccessToken.TokenType.BEARER, token.getTokenValue(),
				token.getIssuedAt(), token.getExpiresAt(), accessTokenContext.getAuthorizedScopes());
		OAuth2TokenFormat accessTokenFormat = accessTokenContext.getRegisteredClient()
			.getTokenSettings()
			.getAccessTokenFormat();
		builder.token(accessToken, (metadata) -> {
			if (token instanceof ClaimAccessor claimAccessor) {
				metadata.put(OAuth2Authorization.Token.CLAIMS_METADATA_NAME, claimAccessor.getClaims());
			}
			metadata.put(OAuth2Authorization.Token.INVALIDATED_METADATA_NAME, false);
			metadata.put(OAuth2TokenFormat.class.getName(), accessTokenFormat.getValue());
		});

		return accessToken;
	}

}

